package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Use DEFAULT CSVFormat instance for testing
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrintCreatesCSVPrinter() throws Exception {
        File mockFile = mock(File.class);
        Charset charset = Charset.forName("UTF-8");

        // Mock CSVPrinter instance
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Spy CSVFormat to override print(File, Charset)
        CSVFormat spyFormat = spy(csvFormat);

        // Override print(File, Charset) to return mocked CSVPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(File.class), any(Charset.class));

        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    public void testPrintThrowsIOException() {
        Charset charset = Charset.forName("UTF-8");

        // Passing null file to cause NullPointerException and simulate error
        assertThrows(NullPointerException.class, () -> {
            csvFormat.print((File) null, charset);
        });
    }
}
